import { useMemo, useState } from "react";
import { motion } from "framer-motion";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";

const FAQS = [
  { q: "What is an arithmetic sequence?", a: "An arithmetic sequence is a list of numbers where the same amount is added or subtracted each time. That amount is called the common difference. For example, 4, 7, 10, 13 is arithmetic because each term increases by 3." },
  { q: "What is a geometric sequence?", a: "A geometric sequence is a list of numbers where each term is multiplied by the same number to get the next term. That multiplier is called the common ratio. For example, 3, 6, 12, 24 is geometric because each term is multiplied by 2." },
  { q: "How do you find the next number in a sequence?", a: "First identify the pattern. If the differences between terms are the same, add the common difference. If the ratios between terms are the same, multiply by the common ratio. More complex sequences may need additional rules." },
  { q: "What is the common difference in an arithmetic sequence?", a: "The common difference is the amount added to each term to get the next term. It is found by subtracting one term from the next, such as d = a2 - a1. In 10, 15, 20, 25, the common difference is 5." },
  { q: "How do you find the nth term of a sequence?", a: "For arithmetic sequences, use an = a1 + (n - 1)d. For geometric sequences, use an = a1 x r^(n - 1). Here a1 is the first term, d is the common difference, r is the common ratio, and n is the term number." },
];

function near(a: number, b: number) {
  return Math.abs(a - b) < 1e-9;
}

export default function NumberSequenceCalculator() {
  const [sequence, setSequence] = useState("2, 4, 6, 8, 10");

  const analysis = useMemo(() => {
    const numbers = sequence.split(",").map((part) => Number(part.trim())).filter((value) => Number.isFinite(value));
    if (numbers.length < 3) return { numbers, type: "Need at least 3 numbers", pattern: "Enter at least 3 comma-separated numbers.", next: [] as number[] };

    const diffs = numbers.slice(1).map((value, index) => value - numbers[index]);
    const arithmetic = diffs.every((diff) => near(diff, diffs[0]));
    const ratios = numbers.slice(1).map((value, index) => numbers[index] !== 0 ? value / numbers[index] : NaN);
    const geometric = ratios.every((ratio) => Number.isFinite(ratio) && near(ratio, ratios[0]));
    const next: number[] = [];

    if (arithmetic) {
      let current = numbers[numbers.length - 1];
      for (let i = 0; i < 5; i += 1) {
        current += diffs[0];
        next.push(current);
      }
      return { numbers, type: "Arithmetic sequence", pattern: `Common difference: ${diffs[0]}`, next };
    }
    if (geometric) {
      let current = numbers[numbers.length - 1];
      for (let i = 0; i < 5; i += 1) {
        current *= ratios[0];
        next.push(current);
      }
      return { numbers, type: "Geometric sequence", pattern: `Common ratio: ${ratios[0]}`, next };
    }
    return { numbers, type: "Pattern not detected", pattern: "This tool currently identifies arithmetic and geometric sequences.", next };
  }, [sequence]);

  return (
    <>
      <SEOHead
        title="Free Number Sequence Calculator Online - Find and Continue Any Sequence Instantly | CalcHive"
        description="Free online number sequence calculator. Identify arithmetic and geometric sequences, find the pattern and calculate the next numbers in any sequence instantly. 100% free, no signup required."
        canonical="/number-sequence-calculator"
        keywords="free number sequence calculator, arithmetic sequence calculator free online, geometric sequence calculator free, find next number in sequence free, sequence pattern calculator free"
        category="Math Calculators"
        faqs={FAQS}
      />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8">
          <span className="text-xs font-semibold uppercase tracking-widest text-amber-600 dark:text-amber-400 bg-amber-50 dark:bg-amber-950/50 px-3 py-1 rounded-full mb-4 inline-block">Math</span>
          <h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Number Sequence Calculator Online</h1>
          <p className="text-muted-foreground leading-relaxed">Use this free number sequence calculator to identify arithmetic and geometric patterns and find next numbers in a sequence free.</p>
        </div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <label htmlFor="sequence" className="text-sm font-semibold text-foreground block mb-2">Sequence</label>
          <textarea id="sequence" value={sequence} onChange={(event) => setSequence(event.target.value)} rows={3} className="w-full px-3 py-2 rounded-xl border border-input bg-background text-foreground text-lg font-bold focus:outline-none focus:ring-2 focus:ring-primary/40 transition-all resize-y" />
          <motion.div key={sequence} initial={{ opacity: 0.7, y: 4 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.25 }} className="mt-8">
            <div className="bg-gradient-to-br from-amber-500 to-amber-700 rounded-2xl p-6 text-center shadow-lg">
              <p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Pattern</p>
              <p className="text-4xl font-black text-white tracking-tight" data-testid="result-pattern">{analysis.type}</p>
              <p className="text-white/80 text-sm mt-2">{analysis.pattern}</p>
            </div>
            <div className="mt-4 bg-accent/60 border border-border rounded-xl p-4">
              <p className="text-xs font-bold uppercase tracking-wide text-muted-foreground mb-2">Next 5 numbers</p>
              <p className="text-2xl font-extrabold text-foreground" data-testid="result-next">{analysis.next.length ? analysis.next.map((value) => Number(value.toFixed(8)).toLocaleString()).join(", ") : "Not available"}</p>
            </div>
          </motion.div>
        </section>
        <ShareButton />

        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">How to Find the Pattern in Any Number Sequence for Free</h2>
          <p className="text-muted-foreground leading-relaxed">Enter at least three numbers. The calculator checks whether the sequence has a constant difference or a constant ratio.</p>
          <h2 className="text-2xl font-bold text-foreground">Arithmetic vs Geometric Sequences Explained</h2>
          <p className="text-muted-foreground leading-relaxed">Arithmetic sequences add the same number each step. Geometric sequences multiply by the same number each step.</p>
          <h2 className="text-2xl font-bold text-foreground">Free Sequence Finder for Students and Everyone</h2>
          <p className="text-muted-foreground leading-relaxed">This sequence pattern calculator free tool helps with homework, test prep, and quick number pattern checks.</p>
        </section>

        <section className="mb-8">
          <h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3>
          <div className="space-y-3">{FAQS.map((faq) => <FAQItem key={faq.q} q={faq.q} a={faq.a} />)}</div>
        </section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" />
        <RelatedTools exclude="/number-sequence-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


